### 修正対象 [`scripts/fugue-execute.mjs`](/Users/masayuki/.claude/skills/orchestra-delegator/scripts/fugue-execute.mjs) ### 修正内容（diff形式） ```diff diff --git a/skills/orchestra-delegator/scripts/fugue-execute.mjs b/skills/orchestra-delegator/scripts/fugue-execute.mjs index 4509b919..bc415028 100644 --- a/skills/orchestra-delegator/scripts/fugue-execute.mjs +++ b/skills/orchestra-delegator/scripts/fugue-execute.mjs @@ -178,6 +178,20 @@ function detectUiTask(task) { return /(\.tsx|\.jsx|react component|ui component|design|layout|css|styled-component|tailwind)/i.test(String(task || "")); } +function classifySovereignty(task, project) { + const text = `${task || ""}
${project || ""}`.toLowerCase(); + if (/ (supabase|stripe|slack|freee|e-stat|note-com|chrome|pencil|excalidraw) /.test(text)) { + return "claude-sovereign"; + } + if (/ (security|ethic|ethics|governance|policy|compliance|privacy|safety|risk|audit) /.test(text)) { + return "claude-sovereign"; + } + if (/ (implement|implementation|code|coding|fix|bug|patch|refactor|test|tests) /.test(text)) { + return "codex-sovereign"; + } + return "claude-sovereign"; +} + function buildRequirementsPacket(task, meta) { return { objective: task, @@ -391,10 +405,13 @@ async function maybeVote(runState, phase, operation, reason, rerun) { } function planningMatrix(runState, feedback = "") { + const sovereigntyNote = runState.sovereignty === "codex-sovereign" + ? "
Sovereignty: codex-sovereign. Claude acts as council only (review-only), not primary implementer." + : ""; return { name: "planning", matrix: { - task: `Create an implementation plan for: ${runState.task}
${feedback}`.trim(), + task: `Create an implementation plan for: ${runState.task}${sovereigntyNote}
${feedback}`.trim(), min_providers: 2, min_lanes: 2, lanes: [ @@ -634,6 +651,7 @@ function buildInitialState(args) { const id = runId(); const meta = classify(args.task); const tier = detectTier(args.task, args.tier); + const sovereignty = classifySovereignty(args.task, args.project); const uiTask = detectUiTask(args.task) && isImplementationTask(args.task); if (uiTask) console.error("UI task detected - Pencil MCP guidance injected"); return { @@ -641,6 +659,7 @@ function buildInitialState(args) { task: args.task, project: args.project || process.cwd(), tier, + sovereignty, uiTask, phase: tier >= 2 ? "awaiting_approval" : "implementation", requirementsPacket: buildRequirementsPacket(args.task, meta), ``` ### 検証結果 `node --check scripts/fugue-execute.mjs` は成功しました。 仮定: `classifySovereignty(task, project)` の `project` はシグネチャ要件に合わせて受け取り、判定文字列にも含めています。影響範囲は [`scripts/fugue-execute.mjs`](/Users/masayuki/.claude/skills/orchestra-delegator/scripts/fugue-execute.mjs) のみです。
